form:Form.form:Scripts:
		function LoadForm()
{             	
	OnLoad();
	if(Ctrl("estado").GetXValue()=="D")
	{                                    
		CtrlEnabled("vgPERSONAL_BASE", false);
		CtrlEnabled("vgPERSONAL", false);
		CtrlEnabled("vgPERSONAL", false);
		CtrlEnabled("vgESTRUCTURA", false);
		CtrlEnabled("vgCLASE", false);
		CtrlEnabled("vgVERSION", false);
		CtrlEnabled("vgVISTA", false);
	}
	if(Ctrl("estado").GetXValue()=="V")
	{
		CtrlEnabled("RECHAZAR", false);
		CtrlEnabled("VIGENTE", false);
	}
	if(Ctrl("estado").GetXValue()=="R")
	{
		CtrlEnabled("vgPERSONAL_BASE", false);
		CtrlEnabled("vgPERSONAL", false);
		CtrlEnabled("vgPERSONAL", false);
		CtrlEnabled("vgESTRUCTURA", false);
		CtrlEnabled("vgCLASE", false);
		CtrlEnabled("vgVERSION", false);
		CtrlEnabled("vgVISTA", false);
	}
	if(Ctrl("estado").GetXValue()=="P")
	{
		CtrlEnabled("DISCONTINUAR", false);
		CtrlEnabled("PLANIFICAR", false);
	}
}


function ExternButtonRefresh()
{                  
	var oi_estructura_root=null;
	var EstData,FirstPer=null;

  //Personal
	CtrlEnabled("LEG_ADD" , false);
	CtrlEnabled("LEG_DEL" , false);
	CtrlEnabled("LEG_RESP", false);

	//Estructura
	CtrlEnabled("ESTR_ADD"    , false);
	CtrlEnabled("ESTR_ADD_FIC", false);
	CtrlEnabled("ESTR_DEL"    , false);
	CtrlEnabled("ESTR_MOVE"   , false);
	CtrlEnabled("ESTR_SPLIT"  , false);
	CtrlEnabled("ESTR_NORESP" , false);     
	CtrlEnabled("ESTR_STAFF"  , false);	

  //Clase
	CtrlEnabled("CLASS_ADD", false);
	CtrlEnabled("CLASS_DEL", false);

  //Vista
	CtrlEnabled("VISTA_ADD", false);
	CtrlEnabled("VISTA_DEL", false);

	//Obtengo la Estructura
	EstData=(g_oi_estr_select!=null?g_lst_Estr["K"+g_oi_estr_select]:null);
	if (g_mode!=2)
	{    
		if (EstData!=null)
		{
			if (EstData.GetAttr("extern")!="1" && EstData.GetAttr("l_staff")!="1" && EstData.GetAttr("fic")!="1")
			{
				if (EstData.GetAttr("vista")!="")
					CtrlEnabled("VISTA_DEL", true);
				else                            
					CtrlEnabled("VISTA_ADD", true);
			}

			if (EstData.GetAttr("extern")=="1")
			{       
				//Clase
				CtrlEnabled("CLASS_DEL", true);
			} else                    
			if (EstData.GetAttr("l_staff")=="1")
			{
				//Estructura
				CtrlEnabled("ESTR_DEL"   , true);
				CtrlEnabled("ESTR_NORESP", EstData.GetAttr("nombre")==""?false:true);
				CtrlEnabled("ESTR_STAFF" , true);
			} else       
			if (EstData.GetAttr("fic")=="1")
			{
				//Estructura
				CtrlEnabled("ESTR_ADD"    , true);
				CtrlEnabled("ESTR_ADD_FIC", true);
				CtrlEnabled("ESTR_DEL"    , true);
				CtrlEnabled("ESTR_MOVE"   , false);
				CtrlEnabled("ESTR_SPLIT"  , false);
				CtrlEnabled("ESTR_NORESP" , false);     
				CtrlEnabled("ESTR_STAFF"  , false);

				//Clase
				CtrlEnabled("CLASS_ADD", true);
			} else
			{                             
				//Estructura
				CtrlEnabled("ESTR_ADD"    , true);
				CtrlEnabled("ESTR_ADD_FIC", true);
				CtrlEnabled("ESTR_DEL"    , g_oi_estr_select!=g_oi_estr_root?true:false);
				CtrlEnabled("ESTR_MOVE"   , g_oi_estr_select!=g_oi_estr_root?true:false);
				CtrlEnabled("ESTR_SPLIT"  , g_oi_estr_select!=g_oi_estr_root?true:false);
				CtrlEnabled("ESTR_NORESP" , EstData.GetAttr("nombre")==""?false:true);     
				CtrlEnabled("ESTR_STAFF"  , (g_oi_estr_select!=g_oi_estr_root && EstData.GetAttr("child_count")=="0")?true:false);

				//Clase
				CtrlEnabled("CLASS_ADD", true);
			}
		}
	} else
	{        

		if (EstData!=null)
		{          
			if (g_oi_estr_select==g_oi_estr2_show)
			{       
				FirstPer=EstData.FindElement("personas");
				if (FirstPer!=null) FirstPer=FirstPer.FirstChild();
				if (FirstPer!=null && FirstPer.GetAttr("resp")!="1") FirstPer=null;

			  //Personal
				CtrlEnabled("LEG_ADD" , true);
				CtrlEnabled("LEG_DEL" , g_oi_legajo_select==null?false:true);
				CtrlEnabled("LEG_RESP", g_oi_legajo_select!=null && (FirstPer==null || (FirstPer!=null && FirstPer.GetAttr("oi_legajo")!=g_oi_legajo_select.toString()))?true:false);
				CtrlEnabled("ESTR_NORESP", FirstPer!=null?true:false);    				
			} 
		}
	}   
}


//Clases         
function AddOrganigrama()
{
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","ADDORG",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" />',new ObjtectResult2(),"");	
}         

function DelOrganigrama()
{                                          
	var EstData;
	if (confirm("¿Está seguro que desea desasociar el Organigrama?"))
	{
		EstData=g_lst_Estr["K"+g_oi_estr_select];
		openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","DELORG",'<ID OI_CLASE_ORG="'+EstData.GetAttr("oi_clase_org")+'" OI_ESTR_PADRE="'+EstData.GetAttr("oi_estr_parent")+'" />',new ObjtectResult2(),"");	
	}
}


//Estructuras    
function AddHijo()
{
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","ADDHIJO",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" VALUE="" />',new ObjtectResult2(),"L");
}               

function AddHijoFicticio()
{
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","ADDHIJOFIC",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" VALUE="" />',new ObjtectResult2(),"L");
}               


function SplitOrganigrama()
{
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.flow","SPLITORG","<ID OI_ESTRUCTURA=\""+g_oi_estr_select+"\"/>",new ObjtectResult2(),"L");	
}

function DelEstructura()
{
	if (confirm("¿Está seguro que desea la eliminar la Estructura? Se eliminará junto con sus dependencias"))
		openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","DELESTR",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" VALUE="" />',new ObjtectResult2(),"L");
}

function MoveEstructura()
{
	var oi_clase_org=QueryCache("qry:FIND_CLASE_ORG",'<PARAM oi_estructura="'+g_oi_estr_select+'" />').GetAttr("oi_clase_org");
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","MOVEESTR",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" oi_clase_org="'+oi_clase_org+'" VALUE="" />',new ObjtectResult2(),"L");
}


function AddLegajo()
{
	var oi_clase_org=QueryCache("qry:FIND_CLASE_ORG",'<PARAM oi_estructura="'+g_oi_estr_select+'" />').GetAttr("oi_clase_org");
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","ADDLEGAJO",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" oi_clase_org="'+oi_clase_org+'" />',new ObjtectResult2(),"L");
}                  

function DelLegajo()
{
	if (confirm("¿Está seguro que desea quitar el Legajo de la Estructura?"))
		openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","DELLEGAJO",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" VALUE="'+g_oi_legajo_select+'" />',new ObjtectResult2(),"L");
}

function AddVista()
{
	var oi_clase_org=QueryCache("qry:FIND_CLASE_ORG",'<PARAM oi_estructura="'+g_oi_estr_select+'" />').GetAttr("oi_clase_org");
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","ADDVISTA",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" oi_clase_org="'+oi_clase_org+'" />',new ObjtectResult2(),"L");
}                  

function DelVista()
{
	EstData=g_lst_Estr["K"+g_oi_estr_select];
	if (confirm("¿Está seguro que desea quitar la Vista?"))
		openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","DELVISTA",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" VALUE="'+EstData.GetAttr("vista")+'" />',new ObjtectResult2(),"L");
}

function SetResponsable()
{
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","SETRESP",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" VALUE="'+g_oi_legajo_select+'" />',new ObjtectResult2(),"L");
}                

function MarkStaff()
{
	EstData=g_lst_Estr["K"+g_oi_estr_select];
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow",(EstData.GetAttr("l_staff")=="1"?"DELSTAFF":"SETSTAFF"),'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" />',new ObjtectResult2(),"L");
}                

function UnSetResponsable()
{                            
	var oi_legajo;

	if (g_mode==2)
	{   
		EstData=g_lst_Estr["K"+g_oi_estr_select]; 
		oi_legajo=EstData.FindElement("personas").FirstChild().GetAttr("oi_legajo");
	} else
	{         
		oi_legajo=g_oi_legajo_select;
	}

	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","UNSETRESP",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" VALUE="'+oi_legajo+'" />',new ObjtectResult2(),"L");
}


function ObjtectResult2()
{        
	this.processResult= function(xmlin)
											{  
												OrgClearCache();
												DrawHTML();
											}											
}

function SearchResult() 
{ 
	this.processResult= function(xmlin)
											{    
												OrgClearCache();
												DrawHTML();
											}			
}
